  const activeDays = boundedInt($env.GITHUB_RADAR_ACTIVE_DAYS || 30, 30, 1, 365);
  const matureMinStars = boundedInt($env.GITHUB_RADAR_MATURE_MIN_STARS || 10000, 10000, 1, 100000000);
  const potentialMinStars = boundedInt($env.GITHUB_RADAR_POTENTIAL_MIN_STARS || 500, 500, 1, 100000000);
