  const growthCandidateLimit = boundedInt($env.GITHUB_RADAR_GROWTH_CANDIDATE_LIMIT || 50, 50, sectionLimit, 100);

  activeSinceDate.setDate(now.getDate() - activeDays);
  const activeSince = fmt(activeSinceDate);
  const weekKey = fmt(thisMonday);
  const baseQuery = `fork:false archived:false pushed:>${activeSince}`;

  const common = {
    trigger_type: triggerType,
    input: inputJson.input || inputJson.command_text || '',
    reportDate: fmt(now),
    weekKey,
    activeSince,
    activeDays,
    sectionLimit,
    matureMinStars,
    potentialMinStars,
    potentialMaxStars,
    growthMinStars,
    growthCandidateLimit,
  };

  const queries = [
    {
      section: 'mature',
      sectionTitle: zh.mature,
      q: `stars:>${matureMinStars} ${baseQuery}`,
      sort: 'stars',
      order: 'desc',
      per_page: sectionLimit,
    },
    {
      section: 'potential',
      sectionTitle: zh.potential,
      q: `stars:${potentialMinStars}..${potentialMaxStars} ${baseQuery}`,
      sort: 'stars',
      order: 'desc',
      per_page: sectionLimit,
