const zh = {
  "mature": "成熟活跃项目",
  "potential": "潜力项目",
  "growthCandidates": "增长候选项目",
  "noDesc": "暂无描述",
  "noRepos": "没有找到符合条件的项目。",
  "language": "语言：",
  "updated": "最近更新：",
  "growthTitle": "三、增长最快项目",
  "syntheticSuffix": "（测试数据，真实增长榜将在下次周报生成）",
  "noRealGrowth": "暂未计算出正增长项目。",
  "noGrowthCandidates": "没有增长候选项目，可降低 GITHUB_RADAR_GROWTH_MIN_STARS。",
  "growthSyntheticLabel": " / 本周（测试）",
  "growthRealLabel": " / 本周",
  "currentStars": "当前 stars：",
  "title": "本周 GitHub 项目雷达",
  "filter": "筛选：非 fork、未归档、最近",
  "filterTail": "天内更新；不限定语言或方向。",
  "matureSection": "一、成熟活跃项目",
  "potentialSection": "二、潜力项目"
};
return (function formatRadarDigest(sourceNodeName, triggerType) {
  const sourceItems = $input.all();
  const queryItems = $(sourceNodeName).all();
  const queries = queryItems.map((item) => item.json);
  const responses = {};

  sourceItems.forEach((item, index) => {
    const query = queries[index];
    if (query) {
      responses[query.section] = item.json || {};
    }
  });

  const firstQuery = queries[0] || {
    trigger_type: triggerType,
    reportDate: new Date().toISOString().slice(0, 10),
    weekKey: new Date().toISOString().slice(0, 10),
    activeSince: '',
    activeDays: 30,
    sectionLimit: 5,
  };
  const sectionLimit = firstQuery.sectionLimit || 5;
  const nowIso = new Date().toISOString();

  const normalizeRepo = (repo) => ({
    full_name: repo.full_name || '',
    html_url: repo.html_url || '',
    description: repo.description || '',
    stargazers_count: Number(repo.stargazers_count || 0),
    language: repo.language || 'Unknown',
    pushed_at: repo.pushed_at || '',
    created_at: repo.created_at || '',
    owner: repo.owner ? { login: repo.owner.login, html_url: repo.owner.html_url } : undefined,
    topics: repo.topics || [],
  });
  const normalizeList = (section) => ((responses[section] || {}).items || []).map(normalizeRepo);
  const formatStars = (value) => Number(value || 0).toLocaleString('en-US');
  const formatDate = (value) => value ? String(value).slice(0, 10) : 'unknown';
  const truncate = (value, maxLength = 90) => {
    const text = String(value || '').replace(/\s+/g, ' ').trim();
    if (!text) return zh.noDesc;
    return text.length > maxLength ? `${text.slice(0, maxLength - 1)}...` : text;
  };

  const matureRepos = normalizeList('mature').slice(0, sectionLimit);
  const potentialRepos = normalizeList('potential').slice(0, sectionLimit);
  const selectedNames = new Set([...matureRepos, ...potentialRepos].map((repo) => repo.full_name));
  const growthCandidates = normalizeList('growth');

  const staticData = $getWorkflowStaticData('global');
  const snapshotStore = staticData.github_project_radar_snapshots || {};
  const previousSnapshot = snapshotStore.previous || {};
  const previousRepos = previousSnapshot.repos || {};
  const hasPreviousSnapshot = Object.keys(previousRepos).length > 0;
  const fakeGrowthSetting = String($env.GITHUB_RADAR_FAKE_GROWTH_ON_FIRST_RUN || 'true').trim().toLowerCase();
  const fakeGrowthOnFirstRun = !['0', 'false', 'no', 'off'].includes(fakeGrowthSetting);

  const syntheticGrowth = (repo, index) => {
    const base = Math.max(25, Math.round(repo.stargazers_count * 0.015));
    return Math.max(1, base - index * 7);
  };
  const growthRepos = growthCandidates
    .map((repo, index) => {
      const previous = previousRepos[repo.full_name];
      const realGrowth = previous ? Math.max(0, repo.stargazers_count - Number(previous.stars || 0)) : 0;
      const growth = hasPreviousSnapshot ? realGrowth : (fakeGrowthOnFirstRun ? syntheticGrowth(repo, index) : 0);
      return {
        ...repo,
        weekly_growth: growth,
        previous_stars: previous ? Number(previous.stars || 0) : null,
        growth_is_synthetic: !hasPreviousSnapshot,
      };
    })
    .filter((repo) => repo.weekly_growth > 0)
    .sort((left, right) => right.weekly_growth - left.weekly_growth)
    .filter((repo) => !selectedNames.has(repo.full_name))
    .slice(0, sectionLimit);

  if (triggerType === 'schedule') {
    const currentRepos = {};
    growthCandidates.forEach((repo) => {
      currentRepos[repo.full_name] = {
        stars: repo.stargazers_count,
        html_url: repo.html_url,
        language: repo.language,
        pushed_at: repo.pushed_at,
      };
    });
    staticData.github_project_radar_snapshots = {
      previous: {
        weekKey: firstQuery.weekKey,
        generated_at: nowIso,
        repos: currentRepos,
      },
      last_compared_snapshot: hasPreviousSnapshot ? previousSnapshot : null,
    };
  }

  const appendRepoSection = (lines, title, repos) => {
    lines.push('');
    lines.push(`${title} Top ${sectionLimit}`);
    if (!repos.length) {
      lines.push(zh.noRepos);
      return;
    }
    repos.forEach((repo, index) => {
      lines.push(`${index + 1}. ${repo.full_name} - ${formatStars(repo.stargazers_count)} stars`);
      lines.push(`   ${truncate(repo.description)}`);
      lines.push(`   ${zh.language}${repo.language} | ${zh.updated}${formatDate(repo.pushed_at)}`);
      lines.push(`   ${repo.html_url}`);
    });
  };

  const appendGrowthSection = (lines, repos) => {
    const suffix = hasPreviousSnapshot ? '' : zh.syntheticSuffix;
    lines.push('');
    lines.push(`${zh.growthTitle} Top ${sectionLimit}${suffix}`);
    if (!repos.length) {
      lines.push(hasPreviousSnapshot ? zh.noRealGrowth : zh.noGrowthCandidates);
      return;
    }
    repos.forEach((repo, index) => {
      const growthLabel = repo.growth_is_synthetic ? zh.growthSyntheticLabel : zh.growthRealLabel;
      lines.push(`${index + 1}. ${repo.full_name} - +${formatStars(repo.weekly_growth)} stars${growthLabel}`);
      lines.push(`   ${zh.currentStars}${formatStars(repo.stargazers_count)}`);
      lines.push(`   ${truncate(repo.description)}`);
      lines.push(`   ${zh.language}${repo.language} | ${zh.updated}${formatDate(repo.pushed_at)}`);
      lines.push(`   ${repo.html_url}`);
    });
  };

  const lines = [
    `${zh.title}\uff08${firstQuery.reportDate}\uff09`,
    `${zh.filter} ${firstQuery.activeDays} ${zh.filterTail}`,
  ];
  appendRepoSection(lines, zh.matureSection, matureRepos);
  appendRepoSection(lines, zh.potentialSection, potentialRepos);
  appendGrowthSection(lines, growthRepos);

  const sections = {
    mature: matureRepos,
    potential: potentialRepos,
    growth: growthRepos,
  };
  const querySummary = Object.fromEntries(queries.map((query) => [query.section, {
    q: query.q,
    sort: query.sort,
    order: query.order,
    per_page: query.per_page,
  }]));

  return [{
    json: {
      text: lines.join('\n'),
      data: {
        reportDate: firstQuery.reportDate,
        weekKey: firstQuery.weekKey,
        activeSince: firstQuery.activeSince,
        activeDays: firstQuery.activeDays,
        sectionLimit,
        growthSnapshotMode: hasPreviousSnapshot ? 'real' : 'synthetic_first_run',
        sections,
      },
      metadata: {
        source: 'github_project_radar',
        trigger_type: triggerType,
        generated_at: nowIso,
        has_previous_growth_snapshot: hasPreviousSnapshot,
        q: querySummary,
      },
    },
  }];
})('Build Command GitHub Queries', 'command');

